"""
Test: Verify that focus({ preventScroll: true }) is used in the comment modal
and focus trap, preventing page scroll when the modal opens.

Since the comment modal requires authentication, this test creates a minimal
page that simulates the exact same focus behavior and verifies no scroll occurs.
"""

from playwright.sync_api import sync_playwright
import sys

# This HTML reproduces the exact same layout as the comment modal:
# - A tall scrollable page (simulating ContentView)
# - An absolutely positioned modal at top:200px with 60% height
# - A textarea at the bottom of the modal (like cm-textarea)
# - A focus trap that fires immediately
# - A delayed focus that fires after 500ms
# Both should use preventScroll: true (matching our fix)
TEST_HTML = """
<!DOCTYPE html>
<html>
<head><style>
  body { margin: 0; height: 3000px; background: #f5f5f5; }
  .page-content { padding: 20px; }
  .modal-container {
    position: absolute;
    top: 200px;
    width: 90%;
    height: 60%;
    background: white;
    border: 1px solid #ccc;
    border-radius: 14px;
    display: flex;
    flex-direction: column;
    z-index: 4;
    overflow: hidden;
  }
  .modal-header { padding: 12px; border-bottom: 1px solid #ccc; flex-shrink: 0; }
  .modal-list { flex: 1; overflow-y: auto; padding: 12px; }
  .modal-input-area { padding: 12px; border-top: 1px solid #ccc; flex-shrink: 0; }
  .modal-textarea {
    width: 100%;
    font-size: 14px;
    padding: 8px;
    border: 1px solid #ccc;
    border-radius: 8px;
    resize: none;
    box-sizing: border-box;
  }
</style></head>
<body>
  <div class="page-content">
    <h1>Long scrollable page</h1>
    <p>Scroll content...</p>
    <button id="open-modal">Open Comment Modal</button>
  </div>

  <div id="modal" class="modal-container" style="display:none;">
    <div class="modal-header">
      <span>Comments</span>
      <button id="close-btn">X</button>
    </div>
    <div class="modal-list">
      <p>Comment 1</p><p>Comment 2</p><p>Comment 3</p>
    </div>
    <div class="modal-input-area">
      <textarea id="comment-textarea" class="modal-textarea"
